   278	    protected boolean isPotentialBeanType(Class<?> type)
   279	    {
   280	        String typeStr = ClassUtil.canBeABeanType(type);
   281	        if (typeStr != null) {
   282	            throw new IllegalArgumentException("Cannot deserialize Class "+type.getName()+" (of type "+typeStr+") as a Bean");
   283	        }
   284	        if (ClassUtil.isProxyType(type)) {
   285	            throw new IllegalArgumentException("Cannot deserialize Proxy class "+type.getName()+" as a Bean");
   286	        }
   287	        // also: can't deserialize some local classes: static are ok; in-method not;
   288	        // other non-static inner classes are ok
   289	        typeStr = ClassUtil.isLocalType(type, true);
   290	        if (typeStr != null) {
   291	            throw new IllegalArgumentException("Cannot deserialize Class "+type.getName()+" (of type "+typeStr+") as a Bean");
   292	        }
   293	        return true;
   294	    }
