   300	    protected boolean isIgnorableType(DeserializationContext ctxt, BeanPropertyDefinition propDef,
   301	            Class<?> type, Map<Class<?>,Boolean> ignoredTypes)
   302	    {
   303	        Boolean status = ignoredTypes.get(type);
   304	        if (status != null) {
   305	            return status.booleanValue();
   306	        }
   307	        // 22-Oct-2016, tatu: Slight check to skip primitives, String
   308	        if ((type == String.class) || type.isPrimitive()) {
   309	            status = Boolean.FALSE;
   310	        } else {
   311	            // 21-Apr-2016, tatu: For 2.8, can specify config overrides
   312	            final DeserializationConfig config = ctxt.getConfig();
   313	            status = config.getConfigOverride(type).getIsIgnoredType();
   314	            if (status == null) {
   315	                AnnotatedClass classAnnotations = ctxt.introspectClassAnnotations(type);
   316	                status = ctxt.getAnnotationIntrospector().isIgnorableType(config, classAnnotations);
   317	                // We default to 'false', i.e. not ignorable
   318	                if (status == null) {
   319	                    status = Boolean.FALSE;
   320	                }
   321	            }
   322	        }
   323	        ignoredTypes.put(type, status);
   324	        return status.booleanValue();
   325	    }
